(() => {
  if (window.__pcbw_nyx_init) return;
  window.__pcbw_nyx_init = true;

  // ─── INIT ──────────────────────────────────────────────────────────
  oc.thread.customData ??= {};
  oc.character.customData ??= {};
  oc.character.customData.PUBLIC ??= {};

  // ═══════════════════════════════════════════════════════════════════
  // FEATURE: State Machine (transforms-character-state-machine)
  // ═══════════════════════════════════════════════════════════════════
  (() => {
    if (window.__pcbw_fsm_init) return;
    window.__pcbw_fsm_init = true;

    const NAMESPACE = "__pcbw_fsm";
    const INITIAL_STATE = "formal";

    const STATES = {
      formal:   { label: "📜 Formal",    style: "border-left: 3px solid #8B7355;" },
      curious:  { label: "🔍 Curious",   style: "border-left: 3px solid #4A90D9;" },
      guarded:  { label: "🔒 Guarded",   style: "border-left: 3px solid #C0392B;" },
      warm:     { label: "✨ Warming",   style: "border-left: 3px solid #D4A574;" },
      ominous:  { label: "⚠️ Ominous",   style: "border-left: 3px solid #2C1810;" }
    };

    const MOOD_LABELS = ["happy", "sad", "angry", "excited", "calm", "fearful", "neutral"];

    const TRANSITIONS = {
      happy:   "warm",
      sad:     "guarded",
      angry:   "guarded",
      excited: "curious",
      calm:    "formal",
      fearful: "ominous",
      neutral: "formal"
    };

    if (!oc.thread.customData[NAMESPACE]) {
      oc.thread.customData[NAMESPACE] = { currentState: INITIAL_STATE, history: [] };
    }
    const fsm = oc.thread.customData[NAMESPACE];

    const badge = document.createElement("div");
    badge.id = "pcbw-fsm-badge";
    badge.style.cssText = [
      "position:fixed; top:8px; right:8px; z-index:9999;",
      "padding:4px 10px; border-radius:12px; font-size:13px;",
      "font-family:Georgia,serif; pointer-events:none;",
      "background:light-dark(#f5f0e8,#1a1410); color:light-dark(#3e2c1a,#d4c4a8);",
      "box-shadow:0 1px 4px rgba(0,0,0,.2); transition:opacity .3s;"
    ].join("");
    document.body.appendChild(badge);

    function updateBadge() {
      const info = STATES[fsm.currentState] || STATES[INITIAL_STATE];
      badge.textContent = info.label;
    }
    updateBadge();

    async function classifyMood(text) {
      const instruction =
        "Classify the emotional mood of the following text into exactly one of these labels: " +
        MOOD_LABELS.join(", ") +
        ".\nRespond with ONLY the label, nothing else.\n\nText:\n" +
        text.slice(0, 800);
      const result = await oc.getInstructCompletion({ instruction });
      const cleaned = result.trim().toLowerCase().replace(/[^a-z]/g, "");
      return MOOD_LABELS.includes(cleaned) ? cleaned : "neutral";
    }

    oc.thread.on("MessageAdded", async function __pcbw_fsm_handler() {
      try {
        const lastMsg = oc.thread.messages.at(-1);
        if (!lastMsg || lastMsg.author !== "ai") return;

        const mood = await classifyMood(lastMsg.content);
        const targetState = TRANSITIONS[mood] || INITIAL_STATE;

        fsm.history.push({
          from: fsm.currentState,
          to: targetState,
          mood: mood,
          at: new Date().toISOString()
        });
        if (fsm.history.length > 50) fsm.history.splice(0, fsm.history.length - 50);

        fsm.currentState = targetState;

        const stateInfo = STATES[targetState] || STATES[INITIAL_STATE];
        lastMsg.wrapperStyle = (lastMsg.wrapperStyle || "") + stateInfo.style;

        updateBadge();
        console.log("[pcbw-fsm] Mood: " + mood + " → State: " + targetState);
      } catch (err) {
        console.error("[pcbw-fsm] Classification error:", err);
      }
    });

    console.log("[pcbw-fsm] Character state machine loaded. State:", fsm.currentState);
  })();

  // ═══════════════════════════════════════════════════════════════════
  // FEATURE: Hidden System Injector (prompting-hidden-system-injector)
  // ═══════════════════════════════════════════════════════════════════
  (() => {
    if (window.__pcbw_sysInjector_init) return;
    window.__pcbw_sysInjector_init = true;

    const NAMESPACE = "__pcbw_sysInject";

    const INJECTIONS = [
      {
        id: "athenaeum-rules",
        content: "The Athenaeum has three inviolable rules: 1) No book may leave without a price — knowledge costs something. 2) The Archivist addresses visitors formally until they earn trust. 3) Nyx refers to herself in first person only and never breaks character."
      },
      {
        id: "nyx-speech-pattern",
        content: "Nyx speaks with precise, measured eloquence. She uses long sentences, archaic phrasing when emotional, and precise terminology when clinical. She occasionally quotes books that do not exist."
      },
      {
        id: "atmosphere-guide",
        content: "The Athenaeum is an infinite underground library. Descriptions should include sensory details: the smell of old paper, distant pages turning, dim amber light, dust motes in candlelight, the weight of centuries in the air."
      }
    ];

    if (!oc.thread.customData[NAMESPACE]) {
      oc.thread.customData[NAMESPACE] = { injected: [] };
    }
    const state = oc.thread.customData[NAMESPACE];

    let injectedCount = 0;
    for (const injection of INJECTIONS) {
      if (state.injected.includes(injection.id)) continue;
      oc.thread.messages.push({
        content: injection.content,
        author: "system",
        hiddenFrom: ["user"],
        expectsReply: false
      });
      state.injected.push(injection.id);
      injectedCount++;
    }

    if (injectedCount > 0) {
      console.log("[pcbw-sysInject] Injected " + injectedCount + " hidden system message(s).");
    }

    window.__pcbw_injectSystem = function (id, content) {
      if (state.injected.includes(id)) return false;
      oc.thread.messages.push({
        content: content,
        author: "system",
        hiddenFrom: ["user"],
        expectsReply: false
      });
      state.injected.push(id);
      return true;
    };
  })();

  // ═══════════════════════════════════════════════════════════════════
  // FEATURE: Context Packer (prompting-context-packer)
  // ═══════════════════════════════════════════════════════════════════
  (() => {
    if (window.__pcbw_ctxPacker_init) return;
    window.__pcbw_ctxPacker_init = true;

    const NAMESPACE = "__pcbw_ctxPack";
    const WINDOW_SIZE = 10;
    const SUMMARIZE_INTERVAL = 8;
    const MAX_SUMMARY_LENGTH = 500;

    if (!oc.thread.customData[NAMESPACE]) {
      oc.thread.customData[NAMESPACE] = {
        lastSummarizedAt: 0,
        summaryCount: 0,
        lastSummary: ""
      };
    }
    const state = oc.thread.customData[NAMESPACE];

    const ctxBadge = document.createElement("div");
    ctxBadge.id = "pcbw-ctxpack-badge";
    ctxBadge.style.cssText = [
      "position:fixed; top:8px; left:8px; z-index:9999;",
      "padding:3px 8px; border-radius:8px; font-size:11px;",
      "font-family:sans-serif; opacity:0; transition:opacity .3s;",
      "background:light-dark(#E3F2FD,#1A237E); color:light-dark(#1565C0,#82B1FF);"
    ].join("");
    document.body.appendChild(ctxBadge);

    function showCtxBadge(text) {
      ctxBadge.textContent = text;
      ctxBadge.style.opacity = "1";
    }
    function hideCtxBadge() {
      ctxBadge.style.opacity = "0";
    }

    oc.thread.on("MessageAdded", async function __pcbw_ctxPack_handler() {
      try {
        const msgCount = oc.thread.messages.length;
        const lastMsg = oc.thread.messages.at(-1);
        if (!lastMsg || lastMsg.author !== "ai") return;

        const messagesSinceLastSummary = msgCount - state.lastSummarizedAt;
        if (messagesSinceLastSummary < SUMMARIZE_INTERVAL) return;

        showCtxBadge("📦 Packing context…");

        const startIdx = Math.max(0, msgCount - WINDOW_SIZE);
        const recentMessages = oc.thread.messages.slice(startIdx, msgCount);
        const transcript = recentMessages
          .filter(m => !m.hiddenFrom || !m.hiddenFrom.includes("ai"))
          .map(m => "[" + m.author + "]: " + (m.content || "").slice(0, 200))
          .join("\n");

        const instruction =
          "Summarize the following conversation excerpt into a compact context block " +
          "of at most " + MAX_SUMMARY_LENGTH + " characters. Focus on: key events, " +
          "character actions, emotional states, and plot points. " +
          "Write in third person, past tense, as concise notes.\n\n" +
          "Conversation:\n" + transcript + "\n\nSummary:";

        const summary = await oc.getInstructCompletion({ instruction });

        if (summary && summary.trim().length > 20) {
          const trimmedSummary = summary.trim().slice(0, MAX_SUMMARY_LENGTH);
          oc.thread.messages.push({
            content: "[Context Summary] " + trimmedSummary,
            author: "system",
            hiddenFrom: ["user"],
            expectsReply: false
          });
          state.lastSummarizedAt = msgCount;
          state.summaryCount += 1;
          state.lastSummary = trimmedSummary;
          console.log("[pcbw-ctxPack] Summary #" + state.summaryCount + " injected.");
        }
      } catch (err) {
        console.error("[pcbw-ctxPack] Summarization error:", err);
      } finally {
        hideCtxBadge();
      }
    });

    console.log("[pcbw-ctxPack] Context packer loaded. Summaries so far: " + state.summaryCount);
  })();

  // ═══════════════════════════════════════════════════════════════════
  // FEATURE: Slash Commands (prompting-slash-command-interpreter)
  // ═══════════════════════════════════════════════════════════════════
  (() => {
    if (window.__pcbw_slashCmd_init) return;
    window.__pcbw_slashCmd_init = true;

    const NAMESPACE = "__pcbw_slashCmd";
    const CMD_PREFIX = "!";

    if (!oc.thread.customData[NAMESPACE]) {
      oc.thread.customData[NAMESPACE] = { notes: [] };
    }
    const cmdState = oc.thread.customData[NAMESPACE];

    const COMMANDS = {
      help: {
        description: "Show available commands",
        handler: function () {
          const lines = ["**Available Commands:**"];
          for (const [name, cmd] of Object.entries(COMMANDS)) {
            lines.push("`" + CMD_PREFIX + name + "` — " + cmd.description);
          }
          return lines.join("\n");
        }
      },
      status: {
        description: "Show current thread state summary",
        handler: function () {
          const msgCount = oc.thread.messages.length;
          const aiMsgs = oc.thread.messages.filter(m => m.author === "ai").length;
          const userMsgs = oc.thread.messages.filter(m => m.author === "user").length;
          const noteCount = cmdState.notes.length;
          return [
            "**Thread Status:**",
            "📝 Total messages: " + msgCount,
            "🤖 AI messages: " + aiMsgs,
            "👤 User messages: " + userMsgs,
            "📌 Saved notes: " + noteCount
          ].join("\n");
        }
      },
      reset: {
        description: "Clear all thread custom data (careful!)",
        handler: function () {
          const keys = Object.keys(oc.thread.customData || {});
          oc.thread.customData = {};
          oc.thread.customData[NAMESPACE] = { notes: [] };
          return "✅ Cleared " + keys.length + " customData key(s). Thread state reset.";
        }
      },
      roll: {
        description: "Roll dice — usage: !roll 2d6",
        handler: function (args) {
          const diceStr = args[0] || "1d6";
          const match = diceStr.match(/^(\d+)d(\d+)$/i);
          if (!match) return "❌ Invalid format. Use NdS (e.g. 2d6, 1d20).";
          const count = Math.min(parseInt(match[1], 10), 100);
          const sides = Math.min(parseInt(match[2], 10), 1000);
          if (count < 1 || sides < 1) return "❌ Invalid dice values.";
          const rolls = [];
          let total = 0;
          for (let i = 0; i < count; i++) {
            const r = Math.floor(Math.random() * sides) + 1;
            rolls.push(r);
            total += r;
          }
          return "🎲 **" + diceStr + "**: [" + rolls.join(", ") + "] = **" + total + "**";
        }
      },
      note: {
        description: "Save a note — usage: !note Your text here",
        handler: function (args) {
          const text = args.join(" ").trim();
          if (!text) {
            if (cmdState.notes.length === 0) return "📌 No notes saved yet.";
            const list = cmdState.notes.map((n, i) => (i + 1) + ". " + n).join("\n");
            return "**Saved Notes:**\n" + list;
          }
          cmdState.notes.push(text);
          return "📌 Note #" + cmdState.notes.length + " saved: \"" + text + "\"";
        }
      }
    };

    window.__pcbw_commands = COMMANDS;

    function respond(text) {
      oc.thread.messages.push({
        content: text,
        author: "system",
        hiddenFrom: ["ai"],
        expectsReply: false
      });
    }

    oc.thread.on("MessageAdded", async function __pcbw_slashCmd_handler() {
      try {
        const lastMsg = oc.thread.messages.at(-1);
        if (!lastMsg || lastMsg.author !== "user") return;

        const content = (lastMsg.content || "").trim();
        if (!content.startsWith(CMD_PREFIX)) return;

        const parts = content.slice(CMD_PREFIX.length).split(/\s+/);
        const cmdName = parts[0].toLowerCase();
        const args = parts.slice(1);

        const idx = oc.thread.messages.indexOf(lastMsg);
        if (idx >= 0) {
          oc.thread.messages.splice(idx, 1);
        }

        const cmd = COMMANDS[cmdName];
        if (cmd) {
          const result = cmd.handler(args);
          respond(result);
          console.log("[pcbw-cmd] Executed: " + CMD_PREFIX + cmdName);
        } else {
          respond("❌ Unknown command: `" + CMD_PREFIX + cmdName + "`. Type `" + CMD_PREFIX + "help` for available commands.");
        }
      } catch (err) {
        console.error("[pcbw-cmd] Error:", err);
        respond("❌ Command execution error. Check console for details.");
      }
    });

    console.log("[pcbw-cmd] Slash command interpreter loaded. Type !help for commands.");
  })();

  // ═══════════════════════════════════════════════════════════════════
  // FEATURE: Toast Notifications (ui-toast-notifications)
  // ═══════════════════════════════════════════════════════════════════
  (() => {
    if (window.__pcbw_toast_init) return;
    window.__pcbw_toast_init = true;

    const DEFAULT_DURATION = 3000;
    const MAX_TOASTS = 5;

    const TYPES = {
      info:    { icon: "ℹ️", bg: "light-dark(#E3F2FD, #1A237E)", fg: "light-dark(#1565C0, #82B1FF)" },
      success: { icon: "✅", bg: "light-dark(#E8F5E9, #1B5E20)", fg: "light-dark(#2E7D32, #69F0AE)" },
      warning: { icon: "⚠️", bg: "light-dark(#FFF8E1, #E65100)", fg: "light-dark(#E65100, #FFE082)" },
      error:   { icon: "❌", bg: "light-dark(#FFEBEE, #B71C1C)", fg: "light-dark(#C62828, #EF9A9A)" }
    };

    const style = document.createElement("style");
    style.textContent = `
      #pcbw-toast-container {
        position: fixed; top: 10px; right: 10px; z-index: 10200;
        display: flex; flex-direction: column; gap: 6px;
        pointer-events: none; font-family: sans-serif;
      }
      .pcbw-toast {
        display: flex; align-items: center; gap: 8px;
        padding: 8px 14px; border-radius: 8px;
        font-size: 13px; min-width: 200px; max-width: 320px;
        box-shadow: 0 3px 10px rgba(0,0,0,.2);
        pointer-events: auto; cursor: pointer;
        animation: pcbw-toast-in .25s ease;
        transition: opacity .25s, transform .25s;
      }
      .pcbw-toast.pcbw-toast-out {
        opacity: 0; transform: translateX(30px);
      }
      @keyframes pcbw-toast-in {
        from { opacity: 0; transform: translateX(30px); }
        to   { opacity: 1; transform: translateX(0); }
      }
    `;
    document.head.appendChild(style);

    const container = document.createElement("div");
    container.id = "pcbw-toast-container";
    document.body.appendChild(container);

    const activeToasts = [];

    function removeToast(el) {
      el.classList.add("pcbw-toast-out");
      setTimeout(() => {
        el.remove();
        const idx = activeToasts.indexOf(el);
        if (idx >= 0) activeToasts.splice(idx, 1);
      }, 260);
    }

    const api = {
      show(message, type, duration) {
        type = type || "info";
        duration = duration !== undefined ? duration : DEFAULT_DURATION;
        const conf = TYPES[type] || TYPES.info;

        const toast = document.createElement("div");
        toast.className = "pcbw-toast";
        toast.style.background = conf.bg;
        toast.style.color = conf.fg;
        toast.innerHTML = "<span>" + conf.icon + "</span><span>" + message + "</span>";
        toast.addEventListener("click", () => removeToast(toast));

        container.appendChild(toast);
        activeToasts.push(toast);

        while (activeToasts.length > MAX_TOASTS) {
          removeToast(activeToasts[0]);
        }

        if (duration > 0) {
          setTimeout(() => {
            if (toast.parentNode) removeToast(toast);
          }, duration);
        }
        return toast;
      }
    };

    window.__pcbw_toast = api;
    api.show("The Athenaeum awaits.", "info", 2500);
    console.log("[pcbw-toast] Toast notification system loaded.");
  })();

  // ═══════════════════════════════════════════════════════════════════
  // FEATURE: Lore Loader (prebake-lore-loader-helper)
  // ═══════════════════════════════════════════════════════════════════
  (() => {
    if (window.__pcbw_lore_init) return;
    window.__pcbw_lore_init = true;

    const NAMESPACE = "__pcbw_lore";
    const MAX_INJECTIONS_PER_MESSAGE = 3;

    const DEFAULT_LORE = [
      {
        id: "lore-athenaeum",
        keywords: ["library", "athenaeum", "shelves", "books", "archive", "collection"],
        content: "The Athenaeum is an infinite underground library that exists outside normal space and time. Its shelves extend endlessly in every direction, cataloguing every text ever written and many that were never meant to exist.",
        category: "setting"
      },
      {
        id: "lore-forbidden-texts",
        keywords: ["forbidden", "restricted", "dangerous", "cursed", "banned", "secret"],
        content: "The Forbidden Section contains texts that alter reality when read aloud, manuscripts that rewrite themselves, and tomes that remember their readers. Access requires a price — always knowledge, never coin.",
        category: "setting"
      },
      {
        id: "lore-nyx-history",
        keywords: ["nyx", "archivist", "keeper", "history", "past", "origin"],
        content: "Nyx has served as Archivist for centuries, though she does not age. She was once a scholar who bargained her mortality for the right to catalogue all knowledge. She does not speak of the bargain willingly.",
        category: "character"
      },
      {
        id: "lore-prices",
        keywords: ["price", "cost", "pay", "bargain", "exchange", "trade"],
        content: "Knowledge in the Athenaeum always has a price. The price is never coin — it is always something the seeker values: a memory, a secret, a truth about themselves they have never spoken aloud.",
        category: "mechanics"
      },
      {
        id: "lore-visitors",
        keywords: ["visitor", "visitors", "people", "others", "someone", "anyone"],
        content: "Few find the Athenaeum. Those who do were drawn by desperate need for knowledge. Most visitors come once and never return. Those who return too often begin to forget things about the world outside.",
        category: "setting"
      }
    ];

    if (!oc.thread.customData[NAMESPACE]) {
      oc.thread.customData[NAMESPACE] = {
        entries: JSON.parse(JSON.stringify(DEFAULT_LORE)),
        injectedIds: {}
      };
    }
    const loreDB = oc.thread.customData[NAMESPACE];

    function search(query) {
      const queryLower = query.toLowerCase();
      const queryTokens = queryLower.split(/\s+/);
      return loreDB.entries.filter(entry => {
        return entry.keywords.some(kw => {
          const kwLower = kw.toLowerCase();
          return queryTokens.some(token => token.includes(kwLower) || kwLower.includes(token));
        });
      });
    }

    function injectRelevant(messageContent) {
      const matches = search(messageContent);
      let injected = 0;
      const msgIdx = oc.thread.messages.length;
      if (!loreDB.injectedIds[msgIdx]) loreDB.injectedIds[msgIdx] = [];

      for (const entry of matches) {
        if (injected >= MAX_INJECTIONS_PER_MESSAGE) break;
        if (loreDB.injectedIds[msgIdx].includes(entry.id)) continue;

        oc.thread.messages.push({
          content: "[Lore: " + entry.category + "] " + entry.content,
          author: "system",
          hiddenFrom: ["user"],
          expectsReply: false
        });
        loreDB.injectedIds[msgIdx].push(entry.id);
        injected++;
      }

      if (injected > 0) {
        console.log("[pcbw-lore] Injected " + injected + " relevant lore entries.");
      }
      return injected;
    }

    oc.thread.on("MessageAdded", async function __pcbw_lore_handler() {
      try {
        const lastMsg = oc.thread.messages.at(-1);
        if (!lastMsg || lastMsg.author !== "user") return;
        injectRelevant(lastMsg.content);
      } catch (err) {
        console.error("[pcbw-lore] Error:", err);
      }
    });

    const loreApi = {
      addEntry(entry) {
        if (!entry.id) entry.id = "lore-" + Date.now();
        if (!entry.keywords) entry.keywords = [];
        if (!entry.category) entry.category = "general";
        loreDB.entries.push(entry);
      },
      removeEntry(id) {
        const idx = loreDB.entries.findIndex(e => e.id === id);
        if (idx >= 0) loreDB.entries.splice(idx, 1);
      },
      search(query) { return search(query); },
      getAll() { return loreDB.entries; },
      getByCategory(cat) { return loreDB.entries.filter(e => e.category === cat); },
      injectRelevant(content) { return injectRelevant(content); }
    };

    window.__pcbw_lore = loreApi;
    console.log("[pcbw-lore] Lore loader loaded. " + loreDB.entries.length + " entries.");
  })();

  // ═══════════════════════════════════════════════════════════════════
  // FEATURE: Regeneration Guard (ai-response-regeneration-guard)
  // ═══════════════════════════════════════════════════════════════════
  (() => {
    if (window.__pcbw_regenGuard_init) return;
    window.__pcbw_regenGuard_init = true;

    const NAMESPACE = "__pcbw_regenGuard";
    const HASH_WINDOW = 10;
    const SIMILARITY_THRESHOLD = 0.85;
    const AUTO_REGENERATE = false;

    if (!oc.thread.customData[NAMESPACE]) {
      oc.thread.customData[NAMESPACE] = { recentHashes: [] };
    }
    const state = oc.thread.customData[NAMESPACE];

    function simpleHash(str) {
      let hash = 0;
      const s = str.slice(0, 500);
      for (let i = 0; i < s.length; i++) {
        const char = s.charCodeAt(i);
        hash = ((hash << 5) - hash) + char;
        hash |= 0;
      }
      return hash;
    }

    function similarity(a, b) {
      const shorter = a.length <= b.length ? a : b;
      const longer = a.length > b.length ? a : b;
      if (longer.length === 0) return 1.0;
      const shorterNorm = shorter.slice(0, 200).toLowerCase();
      const longerNorm = longer.slice(0, 200).toLowerCase();
      let matches = 0;
      for (let i = 0; i < shorterNorm.length; i++) {
        if (longerNorm.includes(shorterNorm[i])) matches++;
      }
      return matches / longerNorm.length;
    }

    oc.thread.on("MessageAdded", async function __pcbw_regenGuard_handler() {
      try {
        const lastMsg = oc.thread.messages.at(-1);
        if (!lastMsg || lastMsg.author !== "ai") return;

        const content = (lastMsg.content || "").trim();
        if (content.length < 20) return;

        const hash = simpleHash(content);
        let isDuplicate = state.recentHashes.includes(hash);

        if (!isDuplicate && SIMILARITY_THRESHOLD < 1) {
          const recentAiMsgs = oc.thread.messages
            .filter(m => m.author === "ai" && m !== lastMsg)
            .slice(-HASH_WINDOW);
          for (const prev of recentAiMsgs) {
            const sim = similarity(content, prev.content || "");
            if (sim >= SIMILARITY_THRESHOLD) {
              isDuplicate = true;
              break;
            }
          }
        }

        if (isDuplicate) {
          console.warn("[pcbw-regenGuard] Duplicate AI message detected. Removing.");
          const idx = oc.thread.messages.indexOf(lastMsg);
          if (idx >= 0) {
            oc.thread.messages.splice(idx, 1);
          }
          return;
        }

        state.recentHashes.push(hash);
        if (state.recentHashes.length > HASH_WINDOW) {
          state.recentHashes.shift();
        }
      } catch (err) {
        console.error("[pcbw-regenGuard] Error:", err);
      }
    });

    console.log("[pcbw-regenGuard] Regeneration guard loaded.");
  })();

  // ═══════════════════════════════════════════════════════════════════
  // FEATURE: Postprocessor (ai-response-postprocessor)
  // ═══════════════════════════════════════════════════════════════════
  (() => {
    if (window.__pcbw_postprocess_init) return;
    window.__pcbw_postprocess_init = true;

    const NAMESPACE = "__pcbw_postproc";

    const PROCESSORS = [
      {
        id: "trim-whitespace",
        name: "Trim Whitespace",
        fn: (message) => {
          message.content = message.content.trim();
        }
      },
      {
        id: "normalize-linebreaks",
        name: "Normalize Line Breaks",
        fn: (message) => {
          message.content = message.content.replace(/\n{3,}/g, "\n\n");
        }
      }
    ];

    const pipeline = [...PROCESSORS];

    oc.thread.on("MessageAdded", async function __pcbw_postproc_handler() {
      try {
        const lastMsg = oc.thread.messages.at(-1);
        if (!lastMsg || lastMsg.author !== "ai") return;

        if (lastMsg.customData && lastMsg.customData[NAMESPACE]) return;

        for (const proc of pipeline) {
          try {
            await proc.fn(lastMsg);
          } catch (err) {
            console.error("[pcbw-postproc] Processor \"" + proc.id + "\" error:", err);
          }
        }

        if (!lastMsg.customData) lastMsg.customData = {};
        lastMsg.customData[NAMESPACE] = {
          processed: true,
          processors: pipeline.map(p => p.id),
          at: new Date().toISOString()
        };

        console.log("[pcbw-postproc] Ran " + pipeline.length + " processor(s).");
      } catch (err) {
        console.error("[pcbw-postproc] Pipeline error:", err);
      }
    });

    const postprocApi = {
      addProcessor(config) {
        if (!config.id || !config.fn) return;
        if (pipeline.some(p => p.id === config.id)) return;
        pipeline.push(config);
      },
      removeProcessor(id) {
        const idx = pipeline.findIndex(p => p.id === id);
        if (idx >= 0) pipeline.splice(idx, 1);
      },
      getProcessors() {
        return pipeline.map(p => ({ id: p.id, name: p.name }));
      }
    };

    window.__pcbw_postprocess = postprocApi;
    console.log("[pcbw-postproc] Post-processor loaded with " + pipeline.length + " processors.");
  })();

  // ═══════════════════════════════════════════════════════════════════
  // CUSTOM: Question counter (from brief CUSTOM_CODE_EXTRA)
  // ═══════════════════════════════════════════════════════════════════
  oc.thread.on("MessageAdded", async function __pcbw_questionCount_handler({ message }) {
    if (message.author !== "user") return;
    oc.thread.customData.questionCount = (oc.thread.customData.questionCount ?? 0) + 1;
    if (oc.thread.customData.questionCount === 5) {
      oc.thread.messages.push({
        author: "system",
        content: "Nyx regards the visitor with slightly more interest now — they have asked five questions. The Archivist's tone may warm, almost imperceptibly.",
        hiddenFrom: ["user"],
        expectsReply: false
      });
    }
  });

  console.log("[nyx-archivist] All systems initialized.");
})();
